import { withDb } from "./db.mjs";

export async function ensureSchema(client) {
  await client.query(`
    CREATE TABLE IF NOT EXISTS accounts (
      account_id TEXT PRIMARY KEY,
      doc JSONB NOT NULL,
      CONSTRAINT accounts_doc_is_object CHECK (jsonb_typeof(doc) = 'object'),
      CONSTRAINT accounts_doc_has_account_id CHECK (doc ? 'accountId' AND jsonb_typeof(doc->'accountId') = 'string' AND doc->>'accountId' <> ''),
      CONSTRAINT accounts_doc_has_name CHECK (doc ? 'name' AND jsonb_typeof(doc->'name') = 'string' AND doc->>'name' <> ''),
      CONSTRAINT accounts_doc_has_tier CHECK (doc ? 'tier' AND jsonb_typeof(doc->'tier') = 'string' AND (doc->>'tier') IN ('strategic', 'midmarket', 'standard')),
      CONSTRAINT accounts_doc_has_status CHECK (doc ? 'status' AND jsonb_typeof(doc->'status') = 'string' AND (doc->>'status') IN ('active', 'at-risk', 'churned')),
      CONSTRAINT accounts_doc_has_created_at CHECK (doc ? 'createdAt' AND jsonb_typeof(doc->'createdAt') = 'string' AND (doc->>'createdAt')::timestamptz IS NOT NULL),
      CONSTRAINT accounts_doc_account_id_matches CHECK (account_id = doc->>'accountId'),
      CONSTRAINT accounts_doc_tier_valid CHECK (doc->>'tier' IN ('strategic', 'midmarket', 'standard')),
      CONSTRAINT accounts_doc_status_valid CHECK (doc->>'status' IN ('active', 'at-risk', 'churned'))
    )
  `);

  await client.query(`
    CREATE INDEX IF NOT EXISTS accounts_doc_gin_idx
    ON accounts
    USING GIN (doc)
  `);
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}

import { ensureSchema } from "./schema.mjs";

const ALLOWED_TIERS = new Set(["strategic", "midmarket", "standard"]);
const ALLOWED_STATUSES = new Set(["active", "at-risk", "churned"]);

function requireNonEmptyString(value, field) {
  if (typeof value !== "string" || value.trim() === "") {
    throw new Error(`${field} is required`);
  }
  return value;
}

function normalizeCreatedAt(value) {
  const date = value === undefined ? new Date() : new Date(value);
  if (Number.isNaN(date.getTime())) {
    throw new Error("createdAt must be a valid date");
  }
  return date.toISOString();
}

function buildDoc(data = {}, existing = {}) {
  const input = data ?? {};
  const accountId = requireNonEmptyString(input.accountId ?? existing.accountId, "accountId");
  const name = requireNonEmptyString(input.name ?? existing.name, "name");
  const tier = requireNonEmptyString(input.tier ?? existing.tier, "tier");
  const status = requireNonEmptyString(input.status ?? existing.status, "status");

  if (!ALLOWED_TIERS.has(tier)) {
    throw new Error("tier must be one of strategic, midmarket, standard");
  }

  if (!ALLOWED_STATUSES.has(status)) {
    throw new Error("status must be one of active, at-risk, churned");
  }

  return {
    accountId,
    name,
    tier,
    status,
    createdAt: normalizeCreatedAt(input.createdAt ?? existing.createdAt),
  };
}

export async function createAccounts(db, data) {
  await ensureSchema(db);

  const doc = buildDoc(data ?? {});
  const result = await db.query(
    "INSERT INTO accounts (account_id, doc) VALUES ($1, $2::jsonb) RETURNING doc",
    [doc.accountId, doc],
  );

  return result.rows[0]?.doc ?? null;
}

export async function getAccounts(db, id) {
  await ensureSchema(db);

  const result = await db.query(
    "SELECT doc FROM accounts WHERE account_id = $1",
    [id],
  );

  return result.rows[0]?.doc ?? null;
}

export async function updateAccounts(db, id, data) {
  await ensureSchema(db);

  const existingResult = await db.query(
    "SELECT doc FROM accounts WHERE account_id = $1",
    [id],
  );

  const existing = existingResult.rows[0]?.doc;
  if (!existing) {
    return null;
  }

  const doc = buildDoc({ ...(data ?? {}), accountId: id }, existing);
  const result = await db.query(
    "UPDATE accounts SET doc = $2::jsonb WHERE account_id = $1 RETURNING doc",
    [id, doc],
  );

  return result.rows[0]?.doc ?? null;
}

export async function deleteAccounts(db, id) {
  await ensureSchema(db);

  const result = await db.query(
    "DELETE FROM accounts WHERE account_id = $1",
    [id],
  );

  return result.rowCount > 0;
}

